export type Mood = 'Aggressive' | 'Melancholic' | 'Energetic' | 'Chill' | 'Dark' | 'Romantic';
export type Genre = 'Rap/Hip-Hop' | 'R&B' | 'Pop' | 'Rock' | 'Trap';

export interface SongLyrics {
  title: string;
  genre: Genre;
  mood: Mood;
  content: string;
}

export interface RhymeSuggestion {
  word: string;
  score: number;
  type: 'perfect' | 'slant' | 'multi';
}

export type ViewState = 'writer' | 'rhymes' | 'library';

import { GoogleGenAI, Type } from "@google/genai";
import { Genre, Mood } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateLyrics = async (
  topic: string,
  genre: Genre,
  mood: Mood,
  prompt?: string
) => {
  const model = 'gemini-3-flash-preview';
  const systemInstruction = `You are a world-class songwriter at 'Hustle Rec' studios. 
  Your style is modern, clever, and rhythmically precise. 
  You specialize in ${genre} with a ${mood} vibe.
  Provide lyrics structured with [Verse], [Chorus], and [Bridge] tags. 
  Use creative wordplay and metaphors.`;

  const finalPrompt = prompt || `Write a hit ${genre} song about: ${topic}. The mood should be ${mood}.`;

  const response = await ai.models.generateContent({
    model,
    contents: finalPrompt,
    config: {
      systemInstruction,
      temperature: 0.8,
    },
  });

  return response.text || "Failed to generate lyrics. Try a different topic.";
};

export const findRhymes = async (word: string, language: string = "Turkish") => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Find 10 creative rhymes for the word "${word}" in ${language}. 
    Include a mix of perfect rhymes, slant rhymes, and multi-syllabic rhymes.
    Return the response as a JSON array.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            word: { type: Type.STRING },
            score: { type: Type.NUMBER, description: "Rhyme quality 1-10" },
            type: { type: Type.STRING, description: "perfect, slant, or multi" }
          },
          required: ["word", "score", "type"]
        }
      }
    }
  });

  return JSON.parse(response.text || "[]");
};

export const improveLines = async (lines: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Improve these lyrics, make them more poetic and add better flow: \n\n${lines}`,
    config: {
      systemInstruction: "You are an elite ghostwriter. Enhance the provided lyrics without changing the core meaning."
    }
  });

  return response.text || lines;
};

