import React, { useState } from 'react';
import { Wand2, Sparkles, Save, Trash2, Maximize2 } from 'lucide-react';
import { generateLyrics, improveLines } from '../services/geminiService';
import { Genre, Mood } from '../types';

const LyricEditor: React.FC = () => {
  const [lyrics, setLyrics] = useState('');
  const [title, setTitle] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [genre, setGenre] = useState<Genre>('Rap/Hip-Hop');
  const [mood, setMood] = useState<Mood>('Aggressive');
  const [topic, setTopic] = useState('');

  const handleGenerate = async () => {
    if (!topic) return;
    setIsGenerating(true);
    try {
      const result = await generateLyrics(topic, genre, mood);
      setLyrics(result);
    } catch (error) {
      console.error(error);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleImprove = async () => {
    if (!lyrics) return;
    setIsGenerating(true);
    try {
      const improved = await improveLines(lyrics);
      setLyrics(improved);
    } catch (error) {
      console.error(error);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="flex flex-col h-full overflow-hidden animate-in fade-in duration-500">
      <header className="p-6 border-b border-zinc-800 flex items-center justify-between bg-black/50 backdrop-blur-md sticky top-0 z-10">
        <div className="flex-1 max-w-xl">
          <input
            type="text"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="Track Title..."
            className="w-full bg-transparent text-3xl font-bold text-white placeholder-zinc-700 focus:outline-none"
          />
        </div>
        <div className="flex items-center gap-3">
          <button className="p-2 text-zinc-500 hover:text-white transition-colors">
            <Trash2 size={20} />
          </button>
          <button className="flex items-center gap-2 bg-zinc-800 hover:bg-zinc-700 text-white px-4 py-2 rounded-lg transition-colors">
            <Save size={18} />
            <span>Save</span>
          </button>
        </div>
      </header>

      <div className="flex-1 flex overflow-hidden">
        {/* Editor Area */}
        <div className="flex-1 relative overflow-auto p-8">
          <textarea
            value={lyrics}
            onChange={(e) => setLyrics(e.target.value)}
            placeholder="Start writing your hustle..."
            className="w-full h-full bg-transparent text-lg leading-relaxed text-zinc-300 placeholder-zinc-800 resize-none focus:outline-none font-mono"
          />
        </div>

        {/* AI Assistant Sidebar */}
        <div className="w-80 bg-[#080808] border-l border-zinc-800 flex flex-col p-6 overflow-y-auto">
          <div className="mb-8">
            <h3 className="text-sm font-semibold text-zinc-500 uppercase tracking-widest mb-4 flex items-center gap-2">
              <Sparkles size={14} className="text-orange-500" />
              Ghostwriter Engine
            </h3>

            <div className="space-y-4">
              <div>
                <label className="text-xs text-zinc-400 mb-2 block">Topic / Idea</label>
                <input
                  type="text"
                  value={topic}
                  onChange={(e) => setTopic(e.target.value)}
                  placeholder="e.g. Midnight city lights"
                  className="w-full bg-zinc-900 border border-zinc-800 rounded-lg px-3 py-2 text-sm text-zinc-200 focus:border-orange-600 outline-none"
                />
              </div>

              <div className="grid grid-cols-2 gap-2">
                <div>
                  <label className="text-xs text-zinc-400 mb-1 block">Genre</label>
                  <select 
                    value={genre}
                    onChange={(e) => setGenre(e.target.value as Genre)}
                    className="w-full bg-zinc-900 border border-zinc-800 rounded-lg px-2 py-2 text-xs text-zinc-200"
                  >
                    <option>Rap/Hip-Hop</option>
                    <option>Trap</option>
                    <option>R&B</option>
                    <option>Pop</option>
                  </select>
                </div>
                <div>
                  <label className="text-xs text-zinc-400 mb-1 block">Mood</label>
                  <select
                    value={mood}
                    onChange={(e) => setMood(e.target.value as Mood)}
                    className="w-full bg-zinc-900 border border-zinc-800 rounded-lg px-2 py-2 text-xs text-zinc-200"
                  >
                    <option>Aggressive</option>
                    <option>Energetic</option>
                    <option>Chill</option>
                    <option>Dark</option>
                  </select>
                </div>
              </div>

              <button
                onClick={handleGenerate}
                disabled={isGenerating || !topic}
                className="w-full bg-orange-600 hover:bg-orange-700 disabled:bg-zinc-800 disabled:text-zinc-600 text-white font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-2"
              >
                {isGenerating ? <div className="animate-spin rounded-full h-4 w-4 border-2 border-white/20 border-t-white" /> : <Wand2 size={18} />}
                Generate Foundation
              </button>
            </div>
          </div>

          <div className="mt-auto space-y-3">
            <button 
              onClick={handleImprove}
              disabled={isGenerating || !lyrics}
              className="w-full border border-zinc-800 hover:bg-zinc-800 text-zinc-300 py-3 rounded-xl transition-all text-sm font-medium flex items-center justify-center gap-2"
            >
