export default LyricEditor;

import React, { useState } from 'react';
import { Search, Hash, Star } from 'lucide-react';
import { findRhymes } from '../services/geminiService';
import { RhymeSuggestion } from '../types';

const RhymeLab: React.FC = () => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<RhymeSuggestion[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!query) return;
    setIsLoading(true);
    try {
      const rhymes = await findRhymes(query);
      setResults(rhymes);
    } catch (err) {
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-8 animate-in slide-in-from-bottom-4 duration-500">
      <div className="text-center mb-12">
        <h1 className="text-4xl font-bebas tracking-wider text-white mb-2">Rhyme Lab</h1>
        <p className="text-zinc-500">Find the missing link to your bars with AI-powered word matching.</p>
      </div>

      <form onSubmit={handleSearch} className="relative max-w-2xl mx-auto mb-12">
        <input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Enter a word to rhyme with..."
          className="w-full bg-zinc-900 border-2 border-zinc-800 focus:border-orange-600 rounded-2xl px-6 py-4 text-xl text-white placeholder-zinc-600 outline-none transition-all shadow-xl"
        />
        <button
          type="submit"
          disabled={isLoading}
          className="absolute right-3 top-3 bg-orange-600 p-3 rounded-xl text-white hover:bg-orange-700 transition-colors shadow-lg shadow-orange-900/40"
        >
          {isLoading ? <div className="animate-spin h-6 w-6 border-2 border-white/20 border-t-white rounded-full" /> : <Search size={24} />}
        </button>
      </form>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {results.map((item, idx) => (
          <div
            key={idx}
            className="group bg-[#0a0a0a] border border-zinc-800 rounded-xl p-5 hover:border-orange-600/50 transition-all cursor-pointer hover:shadow-2xl hover:shadow-orange-900/10"
          >
            <div className="flex items-start justify-between mb-3">
              <span className="text-2xl font-bold text-white group-hover:text-orange-500 transition-colors">{item.word}</span>
              <span className={`text-[10px] uppercase font-black px-2 py-1 rounded ${
                item.type === 'perfect' ? 'bg-green-600/20 text-green-500' :
                item.type === 'multi' ? 'bg-blue-600/20 text-blue-500' : 'bg-zinc-800 text-zinc-400'
              }`}>
                {item.type}
              </span>
            </div>
            <div className="flex items-center gap-1">
              {[...Array(5)].map((_, i) => (
                <Star
                  key={i}
                  size={12}
                  className={i < Math.round(item.score / 2) ? "text-orange-500 fill-orange-500" : "text-zinc-800"}
                />
              ))}
              <span className="text-xs text-zinc-600 ml-2">Score: {item.score}/10</span>
            </div>
          </div>
        ))}

        {!isLoading && results.length === 0 && query && (
          <div className="col-span-full py-20 text-center border-2 border-dashed border-zinc-800 rounded-3xl">
            <Hash size={48} className="mx-auto text-zinc-800 mb-4" />
            <p className="text-zinc-600">No bars found yet. Let's find those rhymes.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default RhymeLab;

