export type Mood = 'Agresif' | 'Melankolik' | 'Enerjik' | 'Sakin' | 'Karanlık' | 'Romantik';
export type Genre = 'Rap/Hip-Hop' | 'R&B' | 'Pop' | 'Rock' | 'Trap';

export interface SongLyrics {
  title: string;
  genre: Genre;
  mood: Mood;
  content: string;
}

export interface RhymeSuggestion {
  word: string;
  score: number;
  type: 'Tam Kafiye' | 'Yarım Kafiye' | 'Zengin Kafiye' | 'Cinaslı';
  syllables: number;
  usage: string;
}

export type ViewState = 'writer' | 'rhymes' | 'library';

import { GoogleGenAI, Type } from "@google/genai";
import { Genre, Mood } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateLyrics = async (
  topic: string,
  genre: Genre,
  mood: Mood,
  prompt?: string
) => {
  const model = 'gemini-3-flash-preview';
  const systemInstruction = `Sen 'Hustle Rec' stüdyosunda çalışan dünyaca ünlü bir şarkı sözü yazarı ve prodüktörsün. 
  Tarzın modern, zekice kelime oyunları içeren ve ritmik olarak kusursuz. 
  ${genre} türünde ve ${mood} bir modda uzmanlaşmışsın. 
  Şarkı sözlerini [Giriş], [Verse], [Nakarat] ve [Köprü] etiketleriyle yapılandır. 
  Türkçe dilini en yaratıcı şekilde kullan, metaforlara ve iç kafiyelere önem ver.`;

  const finalPrompt = prompt || `Konusu şunun hakkında olan hit bir ${genre} şarkısı yaz: ${topic}. Mod: ${mood}.`;

  const response = await ai.models.generateContent({
    model,
    contents: finalPrompt,
    config: {
      systemInstruction,
      temperature: 0.8,
    },
  });

  return response.text || "Söz üretilemedi. Lütfen farklı bir konu deneyin.";
};

export const findRhymes = async (word: string, syllables: number = 0, detailMode: boolean = false) => {
  const model = detailMode ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';
  const syllableFilter = syllables > 0 ? `Özellikle ${syllables} heceli olanları önceliklendir.` : "";

  const response = await ai.models.generateContent({
    model,
    contents: `"${word}" kelimesi için Türkçe yaratıcı kafiyeler bul. ${syllableFilter} 
    Sonuçları JSON dizisi olarak döndür.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            word: { type: Type.STRING, description: "Kafiyeli kelime" },
            score: { type: Type.NUMBER, description: "Kafiye kalitesi 1-10" },
            type: { type: Type.STRING, description: "Tam Kafiye, Yarım Kafiye, Zengin Kafiye veya Cinaslı" },
            syllables: { type: Type.NUMBER, description: "Kelimenin hece sayısı" },
            usage: { type: Type.STRING, description: "Örnek bir bar/satır içinde kullanımı" }
          },
          required: ["word", "score", "type", "syllables", "usage"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || "[]");
  } catch (e) {
    return [];
  }
};

export const improveLines = async (lines: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Bu şarkı sözlerini geliştir, akışı (flow) iyileştir ve daha vurucu hale getir: \n\n${lines}`,
    config: {
      systemInstruction: "Sen bir 'Ghostwriter' (hayalet yazar) uzmanısın. Sözlerin özünü bozmadan edebi derinlik ve ritim kat."
    }
  });

  return response.text || lines;
};

