import { GoogleGenAI, Type } from "@google/genai";
import { Genre, Mood } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateLyrics = async (
  topic: string,
  genre: Genre,
  mood: Mood,
  prompt?: string
) => {
  const model = 'gemini-3-flash-preview';
  const systemInstruction = `Sen 'Hustle Rec' stüdyosunda çalışan dünyaca ünlü bir şarkı sözü yazarı ve prodüktörsün. 
  Tarzın modern, zekice kelime oyunları içeren ve ritmik olarak kusursuz. 
  ${genre} türünde ve ${mood} bir modda uzmanlaşmışsın. 
  Şarkı sözlerini [Giriş], [Verse], [Nakarat] ve [Köprü] etiketleriyle yapılandır. 
  Türkçe dilini en yaratıcı şekilde kullan, metaforlara ve iç kafiyelere önem ver.`;

  const finalPrompt = prompt || `Konusu şunun hakkında olan hit bir ${genre} şarkısı yaz: ${topic}. Mod: ${mood}.`;

  const response = await ai.models.generateContent({
    model,
    contents: finalPrompt,
    config: {
      systemInstruction,
      temperature: 0.8,
    },
  });

  return response.text || "Söz üretilemedi. Lütfen farklı bir konu deneyin.";
};

export const findRhymes = async (
  query: string, 
  syllables: number = 0, 
  mode: 'word' | 'suffix' | 'pattern' = 'word',
  rhymeType: string = 'Hepsi'
) => {
  const model = 'gemini-3-flash-preview';

  const prompt = `"${query}" sorgusu için Türkçe teknik kafiye analizi yap. 
  Arama Modu: ${mode} (kelime sonu, tam kelime veya desen).
  Filtreler: ${syllables > 0 ? syllables + ' heceli olsun.' : 'Hece sınırı yok.'} 
  Kafiye Türü: ${rhymeType}.

  Lütfen şu teknik detayları içeren bir JSON dizisi döndür:
  - word: Kelime
  - score: 1-10 arası kalite puanı
  - type: Tam, Yarım, Zengin, Tunç veya Cinaslı
  - syllables: Hece sayısı
  - ending: Kafiye oluşturan son ek/ses grubu
  - usage: Rap/Şiir içinde örnek kullanım
  - popularity: Kullanım sıklığı (Yüksek, Orta, Düşük)`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            word: { type: Type.STRING },
            score: { type: Type.NUMBER },
            type: { type: Type.STRING },
            syllables: { type: Type.NUMBER },
            ending: { type: Type.STRING },
            usage: { type: Type.STRING },
            popularity: { type: Type.STRING }
          },
          required: ["word", "score", "type", "syllables", "ending", "usage", "popularity"]
        }
      }
    }
  });

  try {
    return JSON.parse(response.text || "[]");
  } catch (e) {
    return [];
  }
};

export const improveLines = async (lines: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Bu şarkı sözlerini geliştir, akışı (flow) iyileştir ve daha vurucu hale getir: \n\n${lines}`,
    config: {
      systemInstruction: "Sen bir 'Ghostwriter' (hayalet yazar) uzmanısın. Sözlerin özünü bozmadan edebi derinlik ve ritim kat."
    }
  });

  return response.text || lines;
};

