  { id: 'fineline', name: 'İnce Çizgi', imageUrl: './UygulamaTeknigi/incecizgi.png', promptFragment: 'Ultra-thin elegant lines, delicate needle work, no heavy outlines' },
  { id: 'dotwork', name: 'Noktalama', imageUrl: './UygulamaTeknigi/noktalama.png', promptFragment: 'Complex stippling, pointillism shading, thousands of tiny dots for depth' },
  { id: 'whipshade', name: 'Whip Shade', imageUrl: './UygulamaTeknigi/whipshade.png', promptFragment: 'Tapered whip shading, pepper shading, fast hand-motion texture' },
  { id: 'blackwork', name: 'Blackwork', imageUrl: './UygulamaTeknigi/blackwork.png', promptFragment: 'Heavy solid black saturation, high contrast black fields' },
  { id: 'watercolor', name: 'Suluboya', imageUrl: './UygulamaTeknigi/suluboya.png', promptFragment: 'Soft color bleed, watercolor brush strokes, no rigid boundaries' },
  { id: 'geometric', name: 'Geometrik', imageUrl: './UygulamaTeknigi/geometrik.png', promptFragment: 'Perfect mathematical symmetry, sacred geometry, clean sharp intersections' }
];

const colorSchemes = [
  { id: 'bw', name: 'Siyah & Gri', value: 'monochromatic black and grey shading', class: 'bg-zinc-700' },
  { id: 'full', name: 'Renkli', value: 'vibrant cinematic full color palette', class: 'bg-gradient-to-br from-red-500 via-green-500 to-blue-500' },
  { id: 'trash', name: 'Trash Kırmızı', value: 'strictly black and red high contrast', class: 'bg-gradient-to-r from-black to-red-600' },
  { id: 'neon', name: 'Cyber Neon', value: 'dark with glowing neon accents', class: 'bg-gradient-to-r from-purple-600 to-cyan-400' },
  { id: 'solid', name: 'Tam Siyah', value: 'heavy solid black ink only', class: 'bg-black border border-white/20' }
];

const bodyPlacements = ['Ön Kol', 'Üst Kol', 'Sırt', 'Göğüs', 'Üst Bacak', 'Boyun', 'El'];
const complexityLevels = ['Sade', 'Orta Detay', 'Yüksek Detay', 'Ustalık Eseri'];

export const AIGenerator: React.FC = () => {
  const { currentUser } = useAuth();
  const [activeTab, setActiveTab] = useState<'art' | 'drafts'>('art');
  const [userPrompt, setUserPrompt] = useState('');
  const [selectedStyle, setSelectedStyle] = useState<VisualOption>(styles[0]);
  const [selectedTechnique, setSelectedTechnique] = useState<VisualOption>(techniques[0]);
  const [selectedColor, setSelectedColor] = useState(colorSchemes[0]);
  const [selectedPlacement, setSelectedPlacement] = useState(bodyPlacements[0]);
  const [selectedComplexity, setSelectedComplexity] = useState(complexityLevels[2]);
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [refinedPromptText, setRefinedPromptText] = useState<string>('');
  const [referenceImage, setReferenceImage] = useState<string | null>(null);
  const [similarity, setSimilarity] = useState<number>(8);
  const [drafts, setDrafts] = useState<Draft[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (currentUser) {
      getUserDrafts(currentUser.uid).then(setDrafts);
    }
  }, [currentUser]);

  const handleCreatePrompt = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    try {
      const refined = await refinePrompt(
        userPrompt, 
        selectedStyle.promptFragment, 
        selectedTechnique.promptFragment, 
        !!referenceImage, 
        similarity,
        selectedColor.value,
        selectedComplexity,
        selectedPlacement
      );
      setRefinedPromptText(refined);
    } catch (err: any) { setError(err.message); }
    finally { setLoading(false); }
  };

  const handleGenerateImage = async () => {
    setLoading(true);
    setStep('Mürekkep cilde işleniyor...');
    setError(null);
    try {
      const imageBase64 = await generateTattooDesign(refinedPromptText, referenceImage);
      setGeneratedImage(imageBase64);
      if (currentUser) {
         const newDraft = await saveDraftToFirestore({
           userId: currentUser.uid, imageUrl: imageBase64, prompt: refinedPromptText,
           originalSubject: userPrompt, timestamp: Date.now()
         });
         setDrafts(prev => [newDraft, ...prev]);
      } 
    } catch (err: any) { setError(err.message); }
    finally { setLoading(false); setStep(''); }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => { setReferenceImage(reader.result as string); };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="pt-24 min-h-screen bg-brand-dark px-4 pb-24">
      <div className="max-w-7xl mx-auto">
        <ScrollReveal>
          <div className="text-center mb-12">
            <h1 className="text-5xl md:text-7xl font-black text-white mb-4 brand-font italic tracking-tighter uppercase">INK ARTIST <span className="text-brand-teal text-glow-teal">AI</span></h1>
            <p className="text-zinc-500 font-black uppercase tracking-widest text-sm">Hassas Tasarım • Gelişmiş Mürekkep Mantığı • Tam Kontrol</p>
          </div>
        </ScrollReveal>

        <div className="flex justify-center gap-4 mb-16">
          <button onClick={() => setActiveTab('art')} className={`px-10 py-3 rounded-full font-black uppercase tracking-widest transition-all ${activeTab === 'art' ? 'bg-brand-teal text-brand-dark shadow-xl shadow-brand-teal/20' : 'bg-brand-navy text-zinc-400 hover:text-brand-teal'}`}>
            Tasarım Laboratuvarı
          </button>
          <button onClick={() => setActiveTab('drafts')} className={`px-10 py-3 rounded-full font-black uppercase tracking-widest transition-all ${activeTab === 'drafts' ? 'bg-brand-teal text-brand-dark shadow-xl shadow-brand-teal/20' : 'bg-brand-navy text-zinc-400 hover:text-brand-teal'}`}>
            Kayıtlı Şablonlarım ({drafts.length})
          </button>
        </div>

        {activeTab === 'art' && (
          <div className="grid lg:grid-cols-12 gap-10">
            {/* Kontroller */}
            <div className="lg:col-span-5 space-y-8">
              {/* Adım 1: Konsept */}
              <div className="bg-brand-navy/30 p-8 rounded-[40px] border border-brand-teal/10 space-y-8">
                <div>
                  <label className="block text-brand-teal text-xs font-black uppercase mb-4 tracking-widest flex items-center gap-2">
                    <Zap size={14} /> 1. Konsept Tanımı
                  </label>
                  <textarea 
                    value={userPrompt} 
                    onChange={(e) => setUserPrompt(e.target.value)} 
                    placeholder="Dövme fikrini tarif et... (Örn: Bir gülün içinden çıkan antik pusula)" 
                    className="w-full h-24 bg-brand-dark border-0 rounded-2xl p-4 text-white focus:ring-2 focus:ring-brand-teal outline-none text-sm font-bold placeholder:text-zinc-700 resize-none" 
                  />
                </div>

                <div>
                   <label className="flex items-center gap-2 text-brand-orange text-xs font-black uppercase mb-4 tracking-widest">
                     <ImageIcon size={14} /> 2. Görsel Referans (Opsiyonel)
                   </label>
                   {!referenceImage ? (
                    <div onClick={() => fileInputRef.current?.click()} className="h-32 border-2 border-dashed border-brand-teal/20 rounded-2xl flex flex-col items-center justify-center cursor-pointer hover:bg-brand-teal/5 transition-all group">
                      <Upload size={24} className="mb-2 text-zinc-600 group-hover:text-brand-teal" />
                      <span className="text-[10px] font-black uppercase text-zinc-600">Referans görselini buraya sürükle</span>
                      <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" />
                    </div>
                  ) : (
                    <div className="space-y-4">
                      <div className="relative h-40 w-full bg-brand-dark rounded-xl overflow-hidden group">
                        <img src={referenceImage} className="w-full h-full object-contain" />
                        <button onClick={() => setReferenceImage(null)} className="absolute top-2 right-2 p-2 bg-brand-dark/80 rounded-full text-brand-orange opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={16}/></button>
                      </div>
                      <div className="space-y-2 px-2">
                        <div className="flex justify-between text-[10px] font-black text-zinc-500 uppercase"><span>Benzerlik</span><span>{similarity}/10</span></div>
                        <input type="range" min="1" max="10" value={similarity} onChange={(e) => setSimilarity(parseInt(e.target.value))} className="w-full accent-brand-teal" />
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Adım 3: Stiller */}
              <div className="bg-brand-navy/30 p-8 rounded-[40px] border border-brand-teal/10">
                <label className="block text-brand-teal text-xs font-black uppercase mb-6 tracking-widest">3. Dövme Stilini Seç</label>
                <div className="grid grid-cols-4 gap-4">
                  {styles.map(s => (
                    <button key={s.id} onClick={() => setSelectedStyle(s)} className="group flex flex-col items-center gap-2 outline-none">
                      <div className={`relative aspect-square w-full rounded-2xl overflow-hidden border-2 transition-all ${selectedStyle.id === s.id ? 'border-brand-teal scale-110 shadow-[0_0_20px_rgba(0,194,203,0.3)]' : 'border-transparent grayscale opacity-40 hover:opacity-100 hover:grayscale-0'}`}>
