                      {/* object-cover class here ensures all images, regardless of resolution, fit the aspect-square container identically */}
                      <div className={`relative aspect-square w-full rounded-2xl overflow-hidden border-2 transition-all ${selectedTechnique.id === t.id ? 'border-brand-orange scale-110 shadow-[0_0_20px_rgba(255,157,0,0.3)]' : 'border-transparent grayscale opacity-40 hover:opacity-100 hover:grayscale-0'}`}>
                        <img src={t.imageUrl} className="w-full h-full object-cover" alt={t.name} />
                      </div>
                      <span className={`text-[9px] font-black uppercase tracking-tighter text-center truncate w-full ${selectedTechnique.id === t.id ? 'text-brand-orange' : 'text-zinc-600'}`}>{t.name}</span>
                    </button>
                  ))}
                </div>
              </div>

              {/* Adım 5: Gelişmiş Ayarlar */}
              <div className="bg-brand-navy/30 p-8 rounded-[40px] border border-brand-teal/10 space-y-8">
                <div>
                   <label className="flex items-center gap-2 text-brand-teal text-xs font-black uppercase mb-6 tracking-widest"><Palette size={14}/> 5. Mürekkep Paleti</label>
                   <div className="flex flex-wrap gap-3">
                      {colorSchemes.map(c => (
                        <button 
                          key={c.id} 
                          onClick={() => setSelectedColor(c)}
                          className={`group relative flex items-center gap-2 px-4 py-2 rounded-full border transition-all ${selectedColor.id === c.id ? 'bg-brand-teal/10 border-brand-teal text-brand-teal' : 'bg-brand-dark/50 border-brand-teal/10 text-zinc-500 hover:border-brand-teal/30'}`}
