            </div>

            {/* Sonuç Alanı */}
            <div className="lg:col-span-7 space-y-8">
               {refinedPromptText && (
                <div className="bg-brand-navy p-8 rounded-[40px] border-2 border-brand-teal/10 animate-in fade-in slide-in-from-top-4">
                  <div className="flex justify-between items-center mb-6">
                    <span className="text-brand-orange text-xs font-black uppercase tracking-widest flex items-center gap-2"><Zap size={14} className="animate-pulse" /> Gelişmiş Mürekkep Komutu</span>
                  </div>
                  <div className="bg-brand-dark/50 p-4 rounded-2xl border border-brand-teal/5">
                    <p className="text-zinc-500 text-xs font-mono leading-relaxed">{refinedPromptText}</p>
                  </div>
                  <button onClick={handleGenerateImage} disabled={loading} className="w-full mt-6 py-6 bg-brand-teal text-brand-dark font-black rounded-3xl hover:bg-brand-orange transition-all uppercase tracking-[0.2em] shadow-2xl shadow-brand-teal/20 flex items-center justify-center gap-3">
                    {loading ? <Loader2 className="animate-spin" /> : <Wand2 />} MÜREKKEBİ ENJEKTE ET
                  </button>
                </div>
              )}

              <div className="aspect-[3/4] w-full bg-brand-navy/10 rounded-[60px] border-4 border-dashed border-brand-teal/5 flex items-center justify-center relative overflow-hidden shadow-inner group">
                {loading && refinedPromptText ? (
                  <div className="text-center p-12 space-y-8">
                    <div className="relative w-32 h-32 mx-auto">
                        <div className="absolute inset-0 border-[6px] border-brand-teal/10 rounded-full"></div>
                        <div className="absolute inset-0 border-[6px] border-brand-teal border-t-brand-orange rounded-full animate-spin"></div>
                    </div>
                    <div className="space-y-3">
                        <p className="text-brand-teal font-black uppercase tracking-[0.3em] text-xl animate-pulse">{step || 'İşleniyor...'}</p>
                        <p className="text-zinc-600 text-[10px] font-black uppercase tracking-widest">Hustle Ink v3.0 Motoru</p>
                    </div>
                  </div>
                ) : generatedImage ? (
                  <div className="p-10 h-full w-full flex flex-col items-center justify-center gap-10 bg-zinc-950/20">
                    <div className="relative group/img">
                      <img src={generatedImage} className="max-h-[500px] object-contain drop-shadow-[0_0_80px_rgba(0,194,203,0.4)] rounded-3xl" />
                      <div className="absolute inset-0 bg-brand-teal/10 opacity-0 group-hover/img:opacity-100 transition-opacity rounded-3xl pointer-events-none"></div>
                    </div>
                    <div className="flex gap-4">
                       <a href={generatedImage} download="hustle-ink-sablon.png" className="flex items-center gap-2 px-12 py-5 bg-white text-brand-dark font-black rounded-full uppercase text-xs tracking-widest hover:bg-brand-teal hover:text-brand-dark transition-all shadow-xl">
                         <Download size={18} /> Şablonu İndir
                       </a>
                       <button onClick={() => setReferenceImage(generatedImage)} className="flex items-center gap-2 px-12 py-5 bg-brand-navy text-brand-teal border border-brand-teal/30 font-black rounded-full uppercase text-xs tracking-widest hover:border-brand-teal transition-all">
                         <Maximize2 size={18} /> Yeniden Tasarla
                       </button>
                    </div>
                  </div>
                ) : (
                  <div className="text-center p-20 opacity-20 group-hover:opacity-40 transition-all duration-700">
                    <Wand2 size={100} className="mx-auto mb-8 text-brand-teal" />
                    <h3 className="font-black uppercase tracking-[0.6em] brand-font text-3xl text-white mb-4 italic">Kasa</h3>
                    <p className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">Dijital iğneler komut bekliyor</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'drafts' && (
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-8 animate-in fade-in duration-700">
            {drafts.length > 0 ? drafts.map((draft) => (
              <div key={draft.id} className="group relative aspect-[3/4] bg-brand-navy rounded-[40px] overflow-hidden border border-brand-teal/5 hover:border-brand-teal/40 transition-all duration-500 shadow-2xl">
                <img src={draft.imageUrl} className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-700 scale-105" />
                <div className="absolute inset-0 bg-gradient-to-t from-brand-dark via-brand-dark/20 to-transparent opacity-0 group-hover:opacity-100 transition-all duration-500 flex flex-col justify-end p-8">
                  <p className="text-[10px] font-black text-brand-teal uppercase tracking-widest mb-6 line-clamp-2">{draft.prompt}</p>
                  <div className="flex gap-3">
                    <button onClick={() => {setGeneratedImage(draft.imageUrl); setActiveTab('art');}} className="flex-grow py-3 bg-brand-teal text-brand-dark rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-white transition-all">Geri Yükle</button>
                    <button onClick={() => deleteDraftFromFirestore(draft.id).then(() => setDrafts(prev => prev.filter(d => d.id !== draft.id)))} className="p-3 bg-red-600/20 text-red-500 rounded-2xl hover:bg-red-600 hover:text-white transition-all"><Trash2 size={16}/></button>
                  </div>
                </div>
              </div>
            )) : (
              <div className="col-span-full py-60 text-center opacity-20">
                <p className="text-zinc-600 font-black uppercase tracking-[0.5em] brand-font text-4xl italic">Kasa Henüz Boş</p>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { ScrollReveal } from '../components/Layout';
import { VisualOption, Draft } from '../types';
import { refinePrompt, generateTattooDesign } from '../services/geminiService';
import { useAuth } from '../context/AuthContext';
import { saveDraftToFirestore, getUserDrafts, deleteDraftFromFirestore } from '../services/firestoreService';
import { 
  Wand2, Loader2, Download, AlertCircle, 
  Image as ImageIcon, Trash2, Upload, Zap, Palette, Layers, Maximize2, Move, PenTool
} from 'lucide-react';

const styles: VisualOption[] = [
  { id: 'realism', name: 'Realizm', imageUrl: 'https://images.unsplash.com/photo-1590247813693-5541d1c609fd?q=80&w=300&h=300&fit=crop&grayscale', promptFragment: 'Hyper-realistic, photorealistic portraiture, smooth transitions, depth and texture' },
  { id: 'minimalist', name: 'Minimalist', imageUrl: 'https://images.unsplash.com/photo-1611501275019-9b5cda994e8d?q=80&w=300&h=300&fit=crop&grayscale', promptFragment: 'Elegant minimalist fine lines, geometric simplicity, delicate single-needle style' },
  { id: 'trashpolka', name: 'Trash Polka', imageUrl: 'https://images.unsplash.com/photo-1550537687-c91072c4792d?q=80&w=300&h=300&fit=crop&grayscale', promptFragment: 'Bold trash polka aesthetic, red and black high contrast collage, chaotic brush strokes' },
  { id: 'ignorant', name: 'Ignorant', imageUrl: 'https://images.unsplash.com/photo-1562967914-01efa7e87832?q=80&w=300&h=300&fit=crop&grayscale', promptFragment: 'Naive ignorant style art, simple raw lines, hand-drawn DIY aesthetic' },
  { id: 'abstract', name: 'Soyut', imageUrl: 'https://images.unsplash.com/photo-1541701494587-cb58502866ab?q=80&w=300&h=300&fit=crop&grayscale', promptFragment: 'Fluid abstract forms, organic flow, non-representational motion' },
  { id: 'glitch', name: 'Glitch Art', imageUrl: 'https://images.unsplash.com/photo-1550745165-9bc0b252726f?q=80&w=300&h=300&fit=crop&grayscale', promptFragment: 'Digital glitch effect, static interference, shifted lines' },
  { id: 'cybersigilism', name: 'Cyber Sigilism', imageUrl: 'https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?q=80&w=300&h=300&fit=crop&grayscale', promptFragment: 'Aggressive sharp bio-organic lines, tribal cyber spikes' },
  { id: 'oldschool', name: 'Old School', imageUrl: 'https://images.unsplash.com/photo-1560707303-4e980ce876ad?q=80&w=300&h=300&fit=crop&grayscale', promptFragment: 'American traditional, bold black outlines, solid color packing' }
];

const techniques: VisualOption[] = [
  { id: 'fineline', name: 'İnce Çizgi', imageUrl: '/UygulamaTeknigi/incecizgi.png', promptFragment: 'Ultra-thin elegant lines, delicate needle work, no heavy outlines' },
  { id: 'dotwork', name: 'Noktalama', imageUrl: '/UygulamaTeknigi/noktalama.png', promptFragment: 'Complex stippling, pointillism shading, thousands of tiny dots for depth' },
  { id: 'whipshade', name: 'Whip Shade', imageUrl: '/UygulamaTeknigi/whipshade.png', promptFragment: 'Tapered whip shading, pepper shading, fast hand-motion texture' },
  { id: 'blackwork', name: 'Blackwork', imageUrl: '/UygulamaTeknigi/blackwork.png', promptFragment: 'Heavy solid black saturation, high contrast black fields' },
  { id: 'watercolor', name: 'Suluboya', imageUrl: '/UygulamaTeknigi/suluboya.png', promptFragment: 'Soft color bleed, watercolor brush strokes, no rigid boundaries' },
  { id: 'geometric', name: 'Geometrik', imageUrl: '/UygulamaTeknigi/geometrik.png', promptFragment: 'Perfect mathematical symmetry, sacred geometry, clean sharp intersections' }
];

const colorSchemes = [
  { id: 'bw', name: 'Siyah & Gri', value: 'monochromatic black and grey shading', class: 'bg-zinc-700' },
  { id: 'full', name: 'Renkli', value: 'vibrant cinematic full color palette', class: 'bg-gradient-to-br from-red-500 via-green-500 to-blue-500' },
  { id: 'trash', name: 'Trash Kırmızı', value: 'strictly black and red high contrast', class: 'bg-gradient-to-r from-black to-red-600' },
  { id: 'neon', name: 'Cyber Neon', value: 'dark with glowing neon accents', class: 'bg-gradient-to-r from-purple-600 to-cyan-400' },
  { id: 'solid', name: 'Tam Siyah', value: 'heavy solid black ink only', class: 'bg-black border border-white/20' }
];

const bodyPlacements = ['Ön Kol', 'Üst Kol', 'Sırt', 'Göğüs', 'Üst Bacak', 'Boyun', 'El'];
const complexityLevels = ['Sade', 'Orta Detay', 'Yüksek Detay', 'Ustalık Eseri'];

export const AIGenerator: React.FC = () => {
  const { currentUser } = useAuth();
  const [activeTab, setActiveTab] = useState<'art' | 'drafts'>('art');
  const [userPrompt, setUserPrompt] = useState('');
  const [selectedStyle, setSelectedStyle] = useState<VisualOption>(styles[0]);
  const [selectedTechnique, setSelectedTechnique] = useState<VisualOption>(techniques[0]);
  const [selectedColor, setSelectedColor] = useState(colorSchemes[0]);
  const [selectedPlacement, setSelectedPlacement] = useState(bodyPlacements[0]);
  const [selectedComplexity, setSelectedComplexity] = useState(complexityLevels[2]);
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [refinedPromptText, setRefinedPromptText] = useState<string>('');
  const [referenceImage, setReferenceImage] = useState<string | null>(null);
  const [similarity, setSimilarity] = useState<number>(8);
  const [drafts, setDrafts] = useState<Draft[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (currentUser) {
      getUserDrafts(currentUser.uid).then(setDrafts);
    }
  }, [currentUser]);

  const handleCreatePrompt = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    try {
      const refined = await refinePrompt(
        userPrompt, 
        selectedStyle.promptFragment, 
        selectedTechnique.promptFragment, 
        !!referenceImage, 
        similarity,
        selectedColor.value,
        selectedComplexity,
        selectedPlacement
      );
      setRefinedPromptText(refined);
    } catch (err: any) { setError(err.message); }
    finally { setLoading(false); }
  };

  const handleGenerateImage = async () => {
    setLoading(true);
    setStep('Mürekkep cilde işleniyor...');
    setError(null);
    try {
      const imageBase64 = await generateTattooDesign(refinedPromptText, referenceImage);
      setGeneratedImage(imageBase64);
      if (currentUser) {
         const newDraft = await saveDraftToFirestore({
           userId: currentUser.uid, imageUrl: imageBase64, prompt: refinedPromptText,
           originalSubject: userPrompt, timestamp: Date.now()
         });
         setDrafts(prev => [newDraft, ...prev]);
      } 
    } catch (err: any) { setError(err.message); }
    finally { setLoading(false); setStep(''); }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => { setReferenceImage(reader.result as string); };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="pt-24 min-h-screen bg-brand-dark px-4 pb-24">
      <div className="max-w-7xl mx-auto">
        <ScrollReveal>
          <div className="text-center mb-12">
            <h1 className="text-5xl md:text-7xl font-black text-white mb-4 brand-font italic tracking-tighter uppercase">INK ARTIST <span className="text-brand-teal text-glow-teal">AI</span></h1>
            <p className="text-zinc-500 font-black uppercase tracking-widest text-sm">Hassas Tasarım • Gelişmiş Mürekkep Mantığı • Tam Kontrol</p>
          </div>
        </ScrollReveal>

        <div className="flex justify-center gap-4 mb-16">
          <button onClick={() => setActiveTab('art')} className={`px-10 py-3 rounded-full font-black uppercase tracking-widest transition-all ${activeTab === 'art' ? 'bg-brand-teal text-brand-dark shadow-xl shadow-brand-teal/20' : 'bg-brand-navy text-zinc-400 hover:text-brand-teal'}`}>
            Tasarım Laboratuvarı
          </button>
          <button onClick={() => setActiveTab('drafts')} className={`px-10 py-3 rounded-full font-black uppercase tracking-widest transition-all ${activeTab === 'drafts' ? 'bg-brand-teal text-brand-dark shadow-xl shadow-brand-teal/20' : 'bg-brand-navy text-zinc-400 hover:text-brand-teal'}`}>
            Kayıtlı Şablonlarım ({drafts.length})
          </button>
        </div>

        {activeTab === 'art' && (
          <div className="grid lg:grid-cols-12 gap-10">
            {/* Kontroller */}
            <div className="lg:col-span-5 space-y-8">
              {/* Adım 1: Konsept */}
              <div className="bg-brand-navy/30 p-8 rounded-[40px] border border-brand-teal/10 space-y-8">
                <div>
                  <label className="block text-brand-teal text-xs font-black uppercase mb-4 tracking-widest flex items-center gap-2">
                    <Zap size={14} /> 1. Konsept Tanımı
                  </label>
                  <textarea 
                    value={userPrompt} 
                    onChange={(e) => setUserPrompt(e.target.value)} 
                    placeholder="Dövme fikrini tarif et... (Örn: Bir gülün içinden çıkan antik pusula)" 
                    className="w-full h-24 bg-brand-dark border-0 rounded-2xl p-4 text-white focus:ring-2 focus:ring-brand-teal outline-none text-sm font-bold placeholder:text-zinc-700 resize-none" 
                  />
                </div>

                <div>
                   <label className="flex items-center gap-2 text-brand-orange text-xs font-black uppercase mb-4 tracking-widest">
                     <ImageIcon size={14} /> 2. Görsel Referans (Opsiyonel)
                   </label>
                   {!referenceImage ? (
                    <div onClick={() => fileInputRef.current?.click()} className="h-32 border-2 border-dashed border-brand-teal/20 rounded-2xl flex flex-col items-center justify-center cursor-pointer hover:bg-brand-teal/5 transition-all group">
                      <Upload size={24} className="mb-2 text-zinc-600 group-hover:text-brand-teal" />
                      <span className="text-[10px] font-black uppercase text-zinc-600">Referans görselini buraya sürükle</span>
                      <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" />
                    </div>
                  ) : (
                    <div className="space-y-4">
                      <div className="relative h-40 w-full bg-brand-dark rounded-xl overflow-hidden group">
                        <img src={referenceImage} className="w-full h-full object-contain" />
                        <button onClick={() => setReferenceImage(null)} className="absolute top-2 right-2 p-2 bg-brand-dark/80 rounded-full text-brand-orange opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={16}/></button>
                      </div>
                      <div className="space-y-2 px-2">
                        <div className="flex justify-between text-[10px] font-black text-zinc-500 uppercase"><span>Benzerlik</span><span>{similarity}/10</span></div>
                        <input type="range" min="1" max="10" value={similarity} onChange={(e) => setSimilarity(parseInt(e.target.value))} className="w-full accent-brand-teal" />
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Adım 3: Stiller */}
              <div className="bg-brand-navy/30 p-8 rounded-[40px] border border-brand-teal/10">
                <label className="block text-brand-teal text-xs font-black uppercase mb-6 tracking-widest">3. Dövme Stilini Seç</label>
                <div className="grid grid-cols-4 gap-4">
                  {styles.map(s => (
                    <button key={s.id} onClick={() => setSelectedStyle(s)} className="group flex flex-col items-center gap-2 outline-none">
                      <div className={`relative aspect-square w-full rounded-2xl overflow-hidden border-2 transition-all ${selectedStyle.id === s.id ? 'border-brand-teal scale-110 shadow-[0_0_20px_rgba(0,194,203,0.3)]' : 'border-transparent grayscale opacity-40 hover:opacity-100 hover:grayscale-0'}`}>
                        <img src={s.imageUrl} className="w-full h-full object-cover" />
                      </div>
                      <span className={`text-[9px] font-black uppercase tracking-tighter text-center truncate w-full ${selectedStyle.id === s.id ? 'text-brand-teal' : 'text-zinc-600'}`}>{s.name}</span>
                    </button>
                  ))}
                </div>
              </div>

              {/* Adım 4: Teknikler */}
              <div className="bg-brand-navy/30 p-8 rounded-[40px] border border-brand-orange/10">
                <label className="block text-brand-orange text-xs font-black uppercase mb-6 tracking-widest flex items-center gap-2">
                  <PenTool size={14} /> 4. Uygulama Tekniği
                </label>
                <div className="grid grid-cols-3 gap-4">
                  {techniques.map(t => (
                    <button key={t.id} onClick={() => setSelectedTechnique(t)} className="group flex flex-col items-center gap-2 outline-none">
                      {/* object-cover class here ensures all images, regardless of resolution, fit the aspect-square container identically */}
                      <div className={`relative aspect-square w-full rounded-2xl overflow-hidden border-2 transition-all ${selectedTechnique.id === t.id ? 'border-brand-orange scale-110 shadow-[0_0_20px_rgba(255,157,0,0.3)]' : 'border-transparent grayscale opacity-40 hover:opacity-100 hover:grayscale-0'}`}>
                        <img src={t.imageUrl} className="w-full h-full object-cover" alt={t.name} />
                      </div>
                      <span className={`text-[9px] font-black uppercase tracking-tighter text-center truncate w-full ${selectedTechnique.id === t.id ? 'text-brand-orange' : 'text-zinc-600'}`}>{t.name}</span>
                    </button>
                  ))}
                </div>
              </div>

              {/* Adım 5: Gelişmiş Ayarlar */}
              <div className="bg-brand-navy/30 p-8 rounded-[40px] border border-brand-teal/10 space-y-8">
                <div>
                   <label className="flex items-center gap-2 text-brand-teal text-xs font-black uppercase mb-6 tracking-widest"><Palette size={14}/> 5. Mürekkep Paleti</label>
                   <div className="flex flex-wrap gap-3">
                      {colorSchemes.map(c => (
                        <button 
                          key={c.id} 
                          onClick={() => setSelectedColor(c)}
                          className={`group relative flex items-center gap-2 px-4 py-2 rounded-full border transition-all ${selectedColor.id === c.id ? 'bg-brand-teal/10 border-brand-teal text-brand-teal' : 'bg-brand-dark/50 border-brand-teal/10 text-zinc-500 hover:border-brand-teal/30'}`}
                        >
                          <div className={`w-3 h-3 rounded-full ${c.class}`}></div>
                          <span className="text-[10px] font-black uppercase">{c.name}</span>
                        </button>
                      ))}
                   </div>
                </div>

                <div className="grid grid-cols-2 gap-6">
                   <div>
                     <label className="flex items-center gap-2 text-brand-teal text-xs font-black uppercase mb-4 tracking-widest"><Move size={14}/> Yerleşim</label>
                     <select 
                       value={selectedPlacement} 
                       onChange={(e) => setSelectedPlacement(e.target.value)}
                       className="w-full bg-brand-dark text-white border border-brand-teal/10 rounded-xl p-3 text-xs font-black uppercase outline-none focus:border-brand-teal"
                     >
                       {bodyPlacements.map(p => <option key={p} value={p}>{p}</option>)}
                     </select>
                   </div>
                   <div>
                     <label className="flex items-center gap-2 text-brand-teal text-xs font-black uppercase mb-4 tracking-widest"><Layers size={14}/> Detay Seviyesi</label>
                     <select 
                       value={selectedComplexity} 
                       onChange={(e) => setSelectedComplexity(e.target.value)}
                       className="w-full bg-brand-dark text-white border border-brand-teal/10 rounded-xl p-3 text-xs font-black uppercase outline-none focus:border-brand-teal"
                     >
                       {complexityLevels.map(l => <option key={l} value={l}>{l}</option>)}
                     </select>
                   </div>
                </div>
              </div>

              <button 
                onClick={handleCreatePrompt}
                disabled={loading || !userPrompt} 
                className="w-full py-6 bg-brand-navy border-2 border-brand-teal/20 text-brand-teal font-black rounded-[24px] hover:bg-brand-teal hover:text-brand-dark transition-all uppercase tracking-[0.3em] text-sm shadow-xl shadow-brand-teal/5 disabled:opacity-50"
              >
                {loading ? <Loader2 className="animate-spin mx-auto" /> : 'TASLAĞI HAZIRLA'}
              </button>
            </div>

            {/* Sonuç Alanı */}
            <div className="lg:col-span-7 space-y-8">
               {refinedPromptText && (
                <div className="bg-brand-navy p-8 rounded-[40px] border-2 border-brand-teal/10 animate-in fade-in slide-in-from-top-4">
                  <div className="flex justify-between items-center mb-6">
                    <span className="text-brand-orange text-xs font-black uppercase tracking-widest flex items-center gap-2"><Zap size={14} className="animate-pulse" /> Gelişmiş Mürekkep Komutu</span>
                  </div>
                  <div className="bg-brand-dark/50 p-4 rounded-2xl border border-brand-teal/5">
                    <p className="text-zinc-500 text-xs font-mono leading-relaxed">{refinedPromptText}</p>
                  </div>
                  <button onClick={handleGenerateImage} disabled={loading} className="w-full mt-6 py-6 bg-brand-teal text-brand-dark font-black rounded-3xl hover:bg-brand-orange transition-all uppercase tracking-[0.2em] shadow-2xl shadow-brand-teal/20 flex items-center justify-center gap-3">
                    {loading ? <Loader2 className="animate-spin" /> : <Wand2 />} MÜREKKEBİ ENJEKTE ET
                  </button>
                </div>
              )}

              <div className="aspect-[3/4] w-full bg-brand-navy/10 rounded-[60px] border-4 border-dashed border-brand-teal/5 flex items-center justify-center relative overflow-hidden shadow-inner group">
                {loading && refinedPromptText ? (
                  <div className="text-center p-12 space-y-8">
                    <div className="relative w-32 h-32 mx-auto">
                        <div className="absolute inset-0 border-[6px] border-brand-teal/10 rounded-full"></div>
                        <div className="absolute inset-0 border-[6px] border-brand-teal border-t-brand-orange rounded-full animate-spin"></div>
                    </div>
                    <div className="space-y-3">
                        <p className="text-brand-teal font-black uppercase tracking-[0.3em] text-xl animate-pulse">{step || 'İşleniyor...'}</p>
                        <p className="text-zinc-600 text-[10px] font-black uppercase tracking-widest">Hustle Ink v3.0 Motoru</p>
                    </div>
                  </div>
                ) : generatedImage ? (
                  <div className="p-10 h-full w-full flex flex-col items-center justify-center gap-10 bg-zinc-950/20">
                    <div className="relative group/img">
                      <img src={generatedImage} className="max-h-[500px] object-contain drop-shadow-[0_0_80px_rgba(0,194,203,0.4)] rounded-3xl" />
                      <div className="absolute inset-0 bg-brand-teal/10 opacity-0 group-hover/img:opacity-100 transition-opacity rounded-3xl pointer-events-none"></div>
                    </div>
                    <div className="flex gap-4">
                       <a href={generatedImage} download="hustle-ink-sablon.png" className="flex items-center gap-2 px-12 py-5 bg-white text-brand-dark font-black rounded-full uppercase text-xs tracking-widest hover:bg-brand-teal hover:text-brand-dark transition-all shadow-xl">
                         <Download size={18} /> Şablonu İndir
                       </a>
                       <button onClick={() => setReferenceImage(generatedImage)} className="flex items-center gap-2 px-12 py-5 bg-brand-navy text-brand-teal border border-brand-teal/30 font-black rounded-full uppercase text-xs tracking-widest hover:border-brand-teal transition-all">
                         <Maximize2 size={18} /> Yeniden Tasarla
                       </button>
                    </div>
                  </div>
                ) : (
                  <div className="text-center p-20 opacity-20 group-hover:opacity-40 transition-all duration-700">
                    <Wand2 size={100} className="mx-auto mb-8 text-brand-teal" />
                    <h3 className="font-black uppercase tracking-[0.6em] brand-font text-3xl text-white mb-4 italic">Kasa</h3>
                    <p className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">Dijital iğneler komut bekliyor</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'drafts' && (
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-8 animate-in fade-in duration-700">
            {drafts.length > 0 ? drafts.map((draft) => (
              <div key={draft.id} className="group relative aspect-[3/4] bg-brand-navy rounded-[40px] overflow-hidden border border-brand-teal/5 hover:border-brand-teal/40 transition-all duration-500 shadow-2xl">
                <img src={draft.imageUrl} className="w-full h-full object-cover grayscale group-hover:grayscale-0 transition-all duration-700 scale-105" />
                <div className="absolute inset-0 bg-gradient-to-t from-brand-dark via-brand-dark/20 to-transparent opacity-0 group-hover:opacity-100 transition-all duration-500 flex flex-col justify-end p-8">
                  <p className="text-[10px] font-black text-brand-teal uppercase tracking-widest mb-6 line-clamp-2">{draft.prompt}</p>
                  <div className="flex gap-3">
                    <button onClick={() => {setGeneratedImage(draft.imageUrl); setActiveTab('art');}} className="flex-grow py-3 bg-brand-teal text-brand-dark rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-white transition-all">Geri Yükle</button>
                    <button onClick={() => deleteDraftFromFirestore(draft.id).then(() => setDrafts(prev => prev.filter(d => d.id !== draft.id)))} className="p-3 bg-red-600/20 text-red-500 rounded-2xl hover:bg-red-600 hover:text-white transition-all"><Trash2 size={16}/></button>
                  </div>
                </div>
              </div>
            )) : (
              <div className="col-span-full py-60 text-center opacity-20">
                <p className="text-zinc-600 font-black uppercase tracking-[0.5em] brand-font text-4xl italic">Kasa Henüz Boş</p>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};
